#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int upperBound(vector<int>& nums, int target) {
        int left = 0, right = nums.size();
        while (left < right) {
            int mid = left + (right - left) / 2;
            if (nums[mid] <= target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    int target;
    if (!(cin >> target)) return 0;
    Solution sol;
    int ans = sol.upperBound(nums, target);
    cout << ans << "\n";
    return 0;
}
